{
  "terms": [
    {
      "term": "TT Earthing System",
      "simpleDefinition": "A system where the installation's earth connection is made through a local earth electrode (rod) driven into the ground.",
      "anchor": "The 'Terra-Terra' system using a ground rod.",
      "misconception": "Thinking all houses have an earth rod; most modern UK homes use the supplier's cable instead."
    },
    {
      "term": "TN-S Earthing System",
      "simpleDefinition": "A system where the neutral and earth conductors are kept separate throughout the entire network from the transformer to the installation.",
      "anchor": "The 'S' stands for Separate conductors.",
      "misconception": "Confusing it with TN-C-S; in TN-S, the earth and neutral never touch after the transformer."
    },
    {
      "term": "TN-C-S Earthing System",
      "simpleDefinition": "A system where neutral and earth are combined in the supply cable but separated once they reach the consumer's property.",
      "anchor": "The 'C' stands for Combined supply, 'S' for Separate installation.",
      "misconception": "Believing the earth and neutral are combined inside the house; they are only combined in the street/supply side."
    },
    {
      "term": "ADS (Automatic Disconnection of Supply)",
      "simpleDefinition": "A safety strategy that uses earthing and protective devices to automatically switch off power during a fault.",
      "anchor": "The 'Safety Trip' system.",
      "misconception": "Thinking ADS is a single part; it is a system of components working together."
    },
    {
      "term": "Circuit Protective Conductor (CPC)",
      "simpleDefinition": "The specific conductor that connects the metal parts of electrical equipment to the main earthing terminal.",
      "anchor": "The green and yellow wire inside a standard cable.",
      "misconception": "Calling it just 'the earth'; its technical name is the CPC."
    },
    {
      "term": "Main Protective Bonding",
      "simpleDefinition": "Conductors that connect metal services like gas and water pipes to the main earthing terminal to keep them at the same potential.",
      "anchor": "The thick earth wire clamped to your incoming water or gas pipe.",
      "misconception": "Thinking bonding is meant to carry fault current from a broken appliance; it is actually to prevent shocks from metal pipes."
    },
    {
      "term": "Supplementary Bonding",
      "simpleDefinition": "Additional earth connections used in high-risk areas, like bathrooms, to connect metal parts together locally.",
      "anchor": "Local safety wiring in a bathroom.",
      "misconception": "Thinking this replaces main bonding; it is an extra layer of safety."
    },
    {
      "term": "Earthing Conductor",
      "simpleDefinition": "The main conductor that connects the installation's Main Earthing Terminal to the means of earthing (the supplier's terminal or an electrode).",
      "anchor": "The 'Master' earth wire for the entire building.",
      "misconception": "Confusing this with a CPC; the earthing conductor is the single main link to the outside world."
    },
    {
      "term": "Protective Devices",
      "simpleDefinition": "Components like MCBs (fuses) or RCDs that physically break the circuit when they detect a fault.",
      "anchor": "The circuit breakers in the consumer unit.",
      "misconception": "Thinking the earth wire alone stops the shock; the earth wire allows the protective device to trip."
    },
    {
      "term": "Earth Electrode",
      "simpleDefinition": "A metal rod, plate, or mesh buried in the ground to provide a physical connection to the Earth's mass.",
      "anchor": "The copper rod driven into the garden soil.",
      "misconception": "Thinking every house needs one; they are primarily used for TT systems."
    }
  ],
  "anchorPhrases": [
    "Identify the earthing arrangement",
    "Components of ADS",
    "Path to the means of earthing",
    "Separate vs Combined conductors"
  ],
  "misconceptionTargets": [
    "Using 'earth wire' as a generic term for CPC, bonding, and earthing conductors.",
    "Assuming all earthing systems use a physical rod in the ground.",
    "Treating TN-S and TN-C-S as the same arrangement."
  ]
}

{
  "teachChecks": [
    {
      "key": "203-4a-teach-check-1",
      "title": "Earthing System Types",
      "objective": "Identify the three main types of earthing systems used in electrical installations.",
      "retrievalTextLines": [
        "Earthing systems are identified by letter codes that describe how the installation connects to the Earth. The first letter 'T' stands for 'Terre' (French for Earth), indicating the power source is connected to the ground. The second letter 'N' stands for 'Neutral'.",
        "In a TN-S system, the 'S' stands for Separate. This means the Neutral and Earth are two distinct conductors throughout the entire network. In a TN-C-S system, the 'C' stands for Combined. Here, the Neutral and Earth are one single conductor in the supply cable but are split into Separate wires once they reach the consumer's property.",
        "A TT system is different because the second 'T' indicates that the consumer must provide their own connection to the Earth. This is done using an earth electrode, which is a metal rod or plate buried in the ground, rather than relying on the supplier's cable for an earth path."
      ],
      "hint": "Remember: S is for Separate, C is for Combined, and the second T in TT means the consumer provides a connection to the 'Terre' via a rod."
    },
    {
      "key": "203-4a-teach-check-2",
      "title": "ADS Component Parts",
      "objective": "Identify the individual components that facilitate Automatic Disconnection of Supply.",
      "retrievalTextLines": [
        "Automatic Disconnection of Supply (ADS) is a safety strategy that uses specific components to stop the flow of electricity during a fault. Each part has a precise technical name and role.",
        "The Circuit Protective Conductor (CPC) is the green and yellow wire that connects the metal parts of a specific circuit to the main earthing terminal. The Earthing Conductor is the single 'master' wire that links that main terminal to the actual means of earthing, such as the supplier's cable or an earth electrode (a rod in the ground).",
        "Protective devices, like MCBs (circuit breakers) or RCDs, are the components that physically trip to disconnect the power. To ensure safety across the whole building, we use Main protective bonding to connect metal gas and water pipes to the earth terminal. In high-risk areas like bathrooms, we may also use Supplementary bonding to provide extra local safety connections between metal parts."
      ],
      "hint": "The CPC is for a specific circuit, while the Earthing Conductor is the main link for the whole building. Bonding is used for metal pipes, not the circuits themselves."
    }
  ]
}

