          "answerGuidance": [
            "Circuit Protective Conductor",
            "CPC"
          ]
        },
        {
          "questionText": "Which ADS component is used to connect metallic gas or water pipes to the main earthing terminal?",
          "answerGuidance": [
            "Main protective bonding",
            "Main bonding",
            "Protective bonding"
          ]
        },
        {
          "questionText": "What is the name of the single conductor that connects the installation's main earthing terminal to the means of earthing?",
